import{_ as e,c as a,S as l,o as n}from"./chunks/framework.BjmDYXuv.js";const u=JSON.parse('{"title":"Admin Dashboard","description":"","frontmatter":{"search":false},"headers":[],"relativePath":"internal/admin.md","filePath":"internal/admin.md","lastUpdated":1775813078000}'),o={name:"internal/admin.md"};function d(i,t,r,s,c,h){return n(),a("div",null,t[0]||(t[0]=[l('<h1 id="admin-dashboard" tabindex="-1">Admin Dashboard <a class="header-anchor" href="#admin-dashboard" aria-label="Permalink to &quot;Admin Dashboard&quot;">​</a></h1><p>The <strong>colliderml-admin</strong> Space is a private Gradio app that exposes operator controls for the ColliderML backend. It lives in <code>colliderml-production/spaces/colliderml-admin/</code> and is deployed to a HuggingFace Space gated behind a shared admin token.</p><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><p>The Space shows a login box on load. Enter the <code>ADMIN_TOKEN</code> value (the same secret set as an env var on the backend). All subsequent API calls include <code>X-Admin-Token: &lt;token&gt;</code> in the request header.</p><p>Backend URL is read from the <code>COLLIDERML_BACKEND</code> env var (default: <code>https://api.colliderml.com</code>).</p><h2 id="tabs" tabindex="-1">Tabs <a class="header-anchor" href="#tabs" aria-label="Permalink to &quot;Tabs&quot;">​</a></h2><h3 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h3><ul><li><strong>Refresh</strong> button fetches <code>GET /admin/usage?limit=50</code></li><li>Displays a bar chart of the top 50 users ranked by node-hours consumed this calendar month</li><li>Summary line: total node-hours, total requests</li></ul><h3 id="analytics" tabindex="-1">Analytics <a class="header-anchor" href="#analytics" aria-label="Permalink to &quot;Analytics&quot;">​</a></h3><p>Three visualisations from the <code>/admin/analytics/*</code> endpoints:</p><table><thead><tr><th style="text-align:left;">Chart</th><th style="text-align:left;">Endpoint</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;">Requests per channel</td><td style="text-align:left;"><code>/admin/analytics/channels</code></td><td style="text-align:left;">Bar chart of count + node-hours per physics channel</td></tr><tr><td style="text-align:left;">Daily node-hours</td><td style="text-align:left;"><code>/admin/analytics/daily?days=30</code></td><td style="text-align:left;">Line chart over the last 30 days</td></tr><tr><td style="text-align:left;">Failure rate</td><td style="text-align:left;"><code>/admin/analytics/failures</code></td><td style="text-align:left;">Single percentage for the current month</td></tr></tbody></table><h3 id="user-management" tabindex="-1">User management <a class="header-anchor" href="#user-management" aria-label="Permalink to &quot;User management&quot;">​</a></h3><table><thead><tr><th style="text-align:left;">Control</th><th style="text-align:left;">Endpoint</th><th style="text-align:left;">Notes</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Grant</strong></td><td style="text-align:left;"><code>POST /admin/grant</code></td><td style="text-align:left;">Fields: <code>hf_username</code>, <code>delta</code> (positive or negative), <code>reason</code></td></tr><tr><td style="text-align:left;"><strong>Ban</strong></td><td style="text-align:left;"><code>POST /admin/ban</code></td><td style="text-align:left;">Sets <code>banned=true</code>; user gets 403 on next request</td></tr><tr><td style="text-align:left;"><strong>Unban</strong></td><td style="text-align:left;"><code>POST /admin/ban</code></td><td style="text-align:left;">Sets <code>banned=false</code></td></tr></tbody></table><p>Grants are recorded in <code>credit_transactions</code> with <code>reason=admin_grant</code>.</p><h3 id="kill-switch" tabindex="-1">Kill switch <a class="header-anchor" href="#kill-switch" aria-label="Permalink to &quot;Kill switch&quot;">​</a></h3><p>Two buttons:</p><table><thead><tr><th style="text-align:left;">Button</th><th style="text-align:left;">Effect</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>FREEZE</strong></td><td style="text-align:left;"><code>POST /admin/freeze?frozen=true</code> — all new simulation submissions return 503</td></tr><tr><td style="text-align:left;"><strong>UNFREEZE</strong></td><td style="text-align:left;"><code>POST /admin/freeze?frozen=false</code> — resume normal operation</td></tr></tbody></table><p>The freeze flag lives in <code>global_config.submissions_frozen</code>. It does <strong>not</strong> cancel jobs already in flight — only prevents new ones.</p><h2 id="kill-switch-procedure" tabindex="-1">Kill switch procedure <a class="header-anchor" href="#kill-switch-procedure" aria-label="Permalink to &quot;Kill switch procedure&quot;">​</a></h2><p>When something goes wrong (runaway costs, NERSC outage, security incident):</p><ol><li>Click <strong>FREEZE</strong> in the admin Space (or <code>curl -X POST /admin/freeze?frozen=true -H &quot;X-Admin-Token: ...&quot;</code>)</li><li>Investigate the issue</li><li>If needed, <strong>Ban</strong> specific users</li><li>Fix the root cause</li><li>Click <strong>UNFREEZE</strong> to resume</li><li>Optionally <strong>Grant</strong> refunds to affected users</li></ol><h2 id="deployment" tabindex="-1">Deployment <a class="header-anchor" href="#deployment" aria-label="Permalink to &quot;Deployment&quot;">​</a></h2><p>The admin Space is synced by <code>colliderml-production/.github/workflows/sync-spaces.yml</code> (matrix entry: <code>colliderml-admin</code>). It is <strong>not</strong> part of the public repo&#39;s <code>sync-spaces.yml</code> workflow.</p><p>Required HuggingFace Space secrets (set manually via Space Settings):</p><table><thead><tr><th style="text-align:left;">Secret</th><th style="text-align:left;">Purpose</th></tr></thead><tbody><tr><td style="text-align:left;"><code>COLLIDERML_BACKEND</code></td><td style="text-align:left;">Backend URL</td></tr><tr><td style="text-align:left;"><code>ADMIN_TOKEN</code></td><td style="text-align:left;">Shared admin secret</td></tr></tbody></table>',25)]))}const f=e(o,[["render",d]]);export{u as __pageData,f as default};
